previewCss:
.darma-loader-darma-custom-457, .darma-loader-darma-custom-457:before, .darma-loader-darma-custom-457:after {
  width: 35px;
   aspect-ratio: 1;
   box-shadow: 0 0 0 3px inset currentColor;
   position: relative;
   animation: 1.5s infinite 0.5s;
   animation-name: darma-loader-darma-custom-457-l7-1,darma-loader-darma-custom-457-l7-2;
}
.darma-loader-darma-custom-457:before, .darma-loader-darma-custom-457:after {
  content: "";
   position: absolute;
   left: calc(100% + 5px);
   animation-delay: 1s,0s;
}
.darma-loader-darma-custom-457:after {
  left: -40px;
   animation-delay: 0s,1s;
}
@keyframes darma-loader-darma-custom-457-l7-1  {
  0%,55%,100% {border-top-left-radius:0;
   border-bottom-right-radius:0}
20%,30% {border-top-left-radius:50%;
  border-bottom-right-radius:50%}
}
@keyframes darma-loader-darma-custom-457-l7-2  {
  0%,55%,100% {border-bottom-left-radius:0;
   border-top-right-radius:0}
20%,30% {border-bottom-left-radius:50%;
  border-top-right-radius:50%}
}

